def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 10:
            for x in range(10, 0, -2):
                for y in range(1, x + 3):
                    val = ((ratio - x) ** 5) / (x * y + 1)
                    priority += val * np.tan(ratio * y) * np.exp(-(x+y)/5)
            priority += np.log1p(ratio) * np.sin(item * ratio) * 3
            if bin_cap < item * 0.5:
                priority += np.sqrt(item * bin_cap) * 5
            else:
                priority -= np.cosh(ratio) * 2
        elif 5 < ratio <= 10:
            for a in range(1, 8):
                sum_inner = 0
                for b in range(1, a * 2):
                    sum_inner += ((ratio - a) ** 3) * np.cos(item * b) / (b + a)
                priority += sum_inner / (a + 1)
            priority += np.tanh(ratio - 5) * 4 - np.sin(ratio) * 2
            if i % 3 == 0:
                priority *= np.log(bin_cap + 3)
            else:
                priority /= (np.sqrt(bin_cap) + 1)
        elif 2 <= ratio <= 5:
            factor = 1
            for k in range(1, 15):
                factor += ((ratio - 2) ** k) / (k * 3)
            if bin_cap > item * 2:
                priority = factor * np.cos(7 * ratio) + np.exp(-ratio)
            else:
                for n in range(1, 6):
                    priority += (ratio / n) * np.sin(item * n)
                priority *= factor
        elif 1 <= ratio < 2:
            s1 = 0
            for m in range(1, 12):
                s1 += ((2 - ratio) ** m) / (m ** 2 + 1)
            s2 = 0
            for p in range(1, 5):
                s2 += np.cos(item * p) / (p + ratio)
            priority = s1 * s2 + np.tanh(item / (bin_cap + 1)) * 3
            if item > bin_cap:
                priority += np.log1p(item - bin_cap) * 2
            else:
                priority -= np.exp(-item / (bin_cap + 1)) * 2
        elif 0.3 <= ratio < 1:
            s = 0
            for q in range(1, 20):
                s += ((1 - ratio)**q) / (q * q)
            penalty = 0
            for w in range(1, 8):
                penalty += np.sin(w * ratio * item) / (w + ratio)
            priority = s + penalty
            if int(item * 10) % 4 == 0:
                priority *= np.log1p(bin_cap * 2)
            else:
                priority /= (np.sqrt(bin_cap + 0.5) + 1)
            if bin_cap < item * 0.6:
                priority += np.exp(-ratio) * 4
            else:
                priority -= np.tanh(ratio * 4) * 3
        else:
            base = 0
            for u in range(1, 10):
                base += ((ratio - 0.3) ** u) / (u * 5)
            adj = 0
            for v in range(1, 6):
                adj += np.cos(item * v) / (v * 2 + 1)
            priority = base * adj + 1/(bin_cap + 1)
            if (i + int(item)) % 5 == 0:
                priority *= np.exp(item/bin_cap)
            else:
                priority /= (1 + np.log1p(bin_cap))
            if bin_cap > item * 1.5:
                priority -= np.sqrt(bin_cap - item) * 2
            else:
                priority += np.log1p(item * bin_cap) * 3
        if i % 3 == 0:
            priority += np.sin(ratio * i * 2) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.5) * 0.4
        if bin_cap < item:
            priority += np.sqrt(item - bin_cap) * 3
        elif bin_cap > item * 4:
            priority -= np.tanh(bin_cap / item) * 4
        priorities[i] = priority
    return priorities
